#!/bin/bash
# Deploy business_identifier.py and updated ai_visibility.py to chaos_tester repo
set -e
cd ~/chaos_tester

# Write business_identifier.py (new file)
echo "Writing modules/business_identifier.py..."
base64 -d > modules/business_identifier.py << 'B64END'

B64END

# Write updated ai_visibility.py
echo "Writing modules/ai_visibility.py..."
base64 -d > modules/ai_visibility.py << 'B64END'

B64END

echo "Files written successfully!"
echo "Verifying..."
head -5 modules/business_identifier.py
echo "---"
head -5 modules/ai_visibility.py
echo "---"
wc -l modules/business_identifier.py modules/ai_visibility.py

echo ""
echo "Committing and pushing..."
git add modules/business_identifier.py modules/ai_visibility.py
git commit -m "Add BusinessIdentifier: smart business name extraction and HQ city lookup

- New modules/business_identifier.py: scrapes website for candidate
  business names from headers, footers, copyright text, entity suffixes
  (LLC, Inc, Corp, etc.), meta tags, and JSON-LD structured data
- Scores candidates using weighted heuristics (entity suffix > copyright
  > header/footer > title/meta) and classifies as business/person/phrase
- Reverse-lookups headquarters city via OpenCorporates and IRS EO APIs
- Updated ai_visibility.py to use BusinessIdentifier pipeline instead
  of simple domain-name parsing, with graceful fallback
- Added holding/consulting industry categories"
git push origin main

echo ""
echo "Deploying to Cloud Run..."
gcloud run deploy chaos-tester --source . --region us-central1 --allow-unauthenticated --project chaos-tester
